diff -ruN --exclude=CVS /usr/ports/security/sshit/Makefile
/tmp/sshit-work/Makefile
--- /usr/ports/security/sshit/Makefile	Thu Jul 27 18:32:55 2006
+++ /tmp/sshit-work/Makefile	Fri Nov  3 02:31:14 2006
@@ -6,8 +6,7 @@
 #

 PORTNAME=	sshit
-PORTVERSION=	0.5
-PORTREVISION=	1
+PORTVERSION=	0.6
 CATEGORIES=	security
 MASTER_SITES=	http://anp.ath.cx/sshit/ \
 		${MASTER_SITE_LOCAL}
@@ -33,7 +32,7 @@
 .endif

 do-install:
-	${INSTALL_SCRIPT} ${WRKSRC}/${PORTNAME}.pl ${PREFIX}/sbin/${PORTNAME}
+	${INSTALL_SCRIPT} ${WRKSRC}/${PORTNAME} ${PREFIX}/sbin/${PORTNAME}
 	${INSTALL_DATA} ${WRKSRC}/${PORTNAME}.conf ${PREFIX}/etc/${PORTNAME}.conf-dist

 post-install:
